#include<bits/stdc++.h>
using namespace std;
long long b[500010];
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        long long lmax,rmax,ans;
    }a[1500010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(node &x,node ls,node rs)
    {
        x.ans=max(ls.ans,rs.ans);
        x.lmax=ls.lmax;
        x.rmax=rs.rmax;
        if(b[ls.r]!=b[rs.l])
        {
            x.ans=max(x.ans,ls.rmax+rs.lmax);
            x.lmax=((ls.lmax==(ls.r-ls.l+1))?(ls.lmax+rs.lmax):(ls.lmax));
            x.rmax=((rs.rmax==(rs.r-rs.l+1))?(ls.rmax+rs.rmax):(rs.rmax));
        }
    }
    void pushup(long long x)
    {
        pushup(a[x],a[a[x].lson],a[a[x].rson]);
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].lmax=a[x].rmax=a[x].ans=1;
            return x;
        }
        long long mid=(l+r)>>1;
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void update(long long x,long long p)
    {
        if(a[x].l>p||a[x].r<p)
        {
            return;
        }
        if(a[x].l==a[x].r)
        {
            a[x].lmax=a[x].rmax=a[x].ans=1;
            return;
        }
        update(a[x].lson,p);
        update(a[x].rson,p);
        pushup(x);
    }
}t;
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    t.init(1,n);
    while(m--)
    {
        long long x;
        scanf("%lld",&x);
        b[x]^=1;
        t.update(1,x);
        printf("%lld\n",t.a[1].ans);
    }
    return 0;
}
